  ('medical-tech-moex-03848', 'medical-tech', 'medical-tech-moex-112-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', 'PCR是是分分子子檢檢驗驗常常用用的的核核酸酸放放大大技技術術，關於延伸技術的敘述，下列何者最正確？', '["nested PCR可提高PCR反應的ssppeecciiffiicciittyy  和sensitivity", "進行semi-nested PCR時，反反應應中中一一共共有有4個primers", "PCR之tailed primer method，可可增增加加PCR的specificity，但不會增加sensitivity", "gap-PCR適合用來偵測核酸點突變"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:16+00:00", "source_pdf_sha1": "a6b98059091a", "answer_pdf_sha1": "1c717052bbab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "112", "exam_name": "112年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 54, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
