  ('medical-tech-moex-03850', 'medical-tech', 'medical-tech-moex-112-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', 'Allele-ssppeecciiffiicc  oolliiggoonnuucclleeoottiiddee  hhyybbrriiddiizzaattiioonn廣泛使用在癌症與遺傳疾病的分子鑑定上，，在探針的設計上，下列敘 述何者最適當？', '["序列長度大約在20個核苷酸左右", "擬偵測之單一核苷酸差異點最好設計在3''末端鹼基位置", "只需設計偵測突變的探針即可", "檢測靈敏度與特異性都很高"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:16+00:00", "source_pdf_sha1": "a6b98059091a", "answer_pdf_sha1": "1c717052bbab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "112", "exam_name": "112年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
